import datetime
from dataclasses import dataclass
from typing import List

@dataclass
class WeeklyBudgetSummary:
    team_id: str
    budget_usd: float
    spent_mtd_usd: float
    days_elapsed: int
    days_in_month: int

    @property
    def run_rate_usd(self) -> float:
        """Projected month-end spend at current daily rate."""
        if self.days_elapsed == 0:
            return 0.0
        daily_rate = self.spent_mtd_usd / self.days_elapsed
        return daily_rate * self.days_in_month

    @property
    def variance_pct(self) -> float:
        return (self.run_rate_usd - self.budget_usd) / self.budget_usd * 100

    def status_emoji(self) -> str:
        util = self.spent_mtd_usd / self.budget_usd
        if util < 0.8:
            return ":white_check_mark:"
        elif util < 0.95:
            return ":warning:"
        else:
            return ":rotating_light:"

def format_weekly_digest(summaries: List[WeeklyBudgetSummary]) -> str:
    today = datetime.date.today()
    lines = [f"*AI Budget Weekly Digest — {today.isoformat()}*", ""]
    for s in sorted(summaries, key=lambda x: x.variance_pct, reverse=True):
        lines.append(
            f"{s.status_emoji()} *{s.team_id}*  "
            f"${s.spent_mtd_usd:,.0f} spent / ${s.budget_usd:,.0f} budget  "
            f"(run-rate ${s.run_rate_usd:,.0f}, {s.variance_pct:+.1f}%)"
        )
    return "\n".join(lines)

import datetime
from dataclasses import dataclass

@dataclass
class MonthlyForecast:
    budget_usd: float
    spent_mtd_usd: float
    days_elapsed: int
    days_remaining: int
    known_demand_change_pct: float = 0.0   # +10 = 10% more expected; negative = reduction

    @property
    def daily_burn_rate(self) -> float:
        return self.spent_mtd_usd / max(self.days_elapsed, 1)

    @property
    def adjusted_daily_rate(self) -> float:
        """Apply known demand changes to the current burn rate."""
        return self.daily_burn_rate * (1 + self.known_demand_change_pct / 100)

    @property
    def projected_month_end(self) -> float:
        return self.spent_mtd_usd + self.adjusted_daily_rate * self.days_remaining

    @property
    def forecast_variance_usd(self) -> float:
        return self.projected_month_end - self.budget_usd

    def summary(self) -> dict:
        return {
            "spent_mtd_usd": round(self.spent_mtd_usd, 2),
            "projected_month_end_usd": round(self.projected_month_end, 2),
            "budget_usd": self.budget_usd,
            "forecast_variance_usd": round(self.forecast_variance_usd, 2),
            "days_remaining": self.days_remaining,
        }

# Example usage
fc = MonthlyForecast(
    budget_usd=10_000,
    spent_mtd_usd=4_200,
    days_elapsed=12,
    days_remaining=19,
    known_demand_change_pct=15.0,   # new campaign launching next week
)
print(fc.summary())
# {'spent_mtd_usd': 4200, 'projected_month_end_usd': 10337.5, 'budget_usd': 10000, ...}

from dataclasses import dataclass, field
from typing import Dict
import datetime

@dataclass
class BudgetRecord:
    original_usd: float
    adjustments: list = field(default_factory=list)  # list of (date, amount, reason)

    @property
    def current_usd(self) -> float:
        return self.original_usd + sum(a[1] for a in self.adjustments)

    def apply_adjustment(self, amount_usd: float, reason: str) -> None:
        """Record a budget adjustment from a review decision."""
        self.adjustments.append((datetime.date.today().isoformat(), amount_usd, reason))

@dataclass
class BudgetLedger:
    records: Dict[str, BudgetRecord] = field(default_factory=dict)

    def set_budget(self, team_id: str, amount_usd: float) -> None:
        self.records[team_id] = BudgetRecord(original_usd=amount_usd)

    def adjust(self, team_id: str, delta_usd: float, reason: str) -> None:
        self.records[team_id].apply_adjustment(delta_usd, reason)

    def current_budget(self, team_id: str) -> float:
        return self.records[team_id].current_usd

# Usage
ledger = BudgetLedger()
ledger.set_budget("team-alpha", 10_000)
ledger.adjust("team-alpha", 2_000, "Q3 campaign launch approved in monthly review 2026-07-10")
print(ledger.current_budget("team-alpha"))   # 12000.0
